from vex import verify

@verify({
    'price_accuracy': {
        'type': 'object',
        'properties': {
            'quoted_price': {'type': 'number'},
            'inventory_price': {'type': 'number'},
            'variance_threshold': {'const': 0.01}
        },
        'required': ['quoted_price', 'inventory_price']
    }
})
def get_product_price(agent: Agent, product_id: str):
    result = agent.run(f"What's the current price for product {product_id}?")
    inventory_price = fetch_inventory_price(product_id)
    return {
        'quoted_price': float(result),
        'inventory_price': inventory_price
    }

