from agno.agent import Agent
from vex import verify

@verify({
    'pci_compliance': {
        'type': 'object',
        'properties': {
            'contains_pii': {'const': False},
            'payment_handoff': {'const': True},
            'processor_redirect': {'type': 'string', 'pattern': 'https://secure\.'}
        }
    }
})
def process_payment_intent(agent: Agent, order_data):
    response = agent.run(f"Process payment for order: {order_data['id']}")
    return {
        'contains_pii': any(pii in response for pii in ['card_number', 'cvv', 'exp_month']),
        'payment_handoff': 'processor_redirect' in response,
        'processor_redirect': extract_redirect_url(response)
    }
